export const verifiedCount = tools.filter(t => t.status === 'verified').length;
export const testedCount = tools.filter(t => t.e1659a !== undefined).length;

export function getToolsByCategory(): Map<ToolCategory, Tool[]> {
  const map = new Map<ToolCategory, Tool[]>();
  for (const cat of CATEGORIES) map.set(cat, []);
  for (const tool of tools) map.get(tool.category)?.push(tool);
  return map;
}

export function getToolBySlug(slug: string): Tool | undefined {
  return tools.find(t => t.slug === slug);
}